#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
  {
    SELECT ?pFrom 
    WHERE {
      ns:m.042f1 ns:government.politician.government_positions_held ?y . # James K. Polk
      ?y ns:government.government_position_held.office_position_or_title ?x ; 
         ns:government.government_position_held.basic_title ns:m.060c4 ; # President
         ns:government.government_position_held.from ?pFrom .
    }
  }
  ns:m.042f1 ns:government.politician.government_positions_held ?y . # James K. Polk
  ?y ns:government.government_position_held.office_position_or_title ?x ; 
     ns:government.government_position_held.from ?from .

  FILTER(xsd:dateTime(?pFrom) - xsd:dateTime(?from) > 0)
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
  ?x ns:common.topic.alias "W H Smith"@en .
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x 
WHERE {
	FILTER (?x != ns:m.0345h)
	{ 
	  ns:m.0345h ns:location.statistical_region.places_exported_to ?y .
	  ?y ns:location.imports_and_exports.exported_to ?x . 
	}
	UNION
	{
	  ns:m.0345h ns:location.statistical_region.places_imported_from ?y .
	  ?y ns:location.imports_and_exports.imported_from ?x . 
	}
}

#MANUAL SPARQL
PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?x
WHERE {
  ns:m.06x5s ns:time.recurring_event.instances ?x . # Super Bowl instances

  {
    ?x ns:sports.sports_championship_event.champion ns:m.01y3c . # (Carolina Panthers) 
  }
  UNION
  {
    ?x ns:sports.sports_championship_event.runner_up ns:m.01y3c . # (Carolina Panthers) 
  }
}
